    43 | 	/**
    44 | 	 * Deserializes a JSON-RPC message from a JSON string into the appropriate message
    45 | 	 * type (request, response, or notification).
    46 | 	 * @param jsonMapper The JSON mapper to use for deserialization
    47 | 	 * @param jsonText The JSON text to deserialize
    48 | 	 * @return The deserialized JSON-RPC message
    49 | 	 * @throws IOException If deserialization fails
    50 | 	 * @throws IllegalArgumentException If the JSON structure doesn't match any known
    51 | 	 * message type
    52 | 	 */
    53 | 	public static JSONRPCMessage deserializeJsonRpcMessage(McpJsonMapper jsonMapper, String jsonText)
    54 | 			throws IOException {
    55 | 
    56 | 		logger.debug("Received JSON message: {}", jsonText);
    57 | 
    58 | 		Map<String, Object> map = jsonMapper.readValue(jsonText, MAP_TYPE_REF);
    59 | 
    60 | 		// Determine message type based on specific JSON structure
    61 | 		if (map.containsKey("method") && map.containsKey("id")) {
    62 | 			return jsonMapper.convertValue(map, JSONRPCRequest.class);
    63 | 		}
    64 | 		else if (map.containsKey("method") && !map.containsKey("id")) {
    65 | 			return jsonMapper.convertValue(map, JSONRPCNotification.class);
    66 | 		}
    67 | 		else if (map.containsKey("result") || map.containsKey("error")) {
    68 | 			return jsonMapper.convertValue(map, JSONRPCResponse.class);
    69 | 		}
    70 | 
    71 | 		throw new IllegalArgumentException("Cannot deserialize JSONRPCMessage: " + jsonText);
    72 | 	}
